{
  "summary": "The extraction failed. While the financial totals (subtotal, tax, total) and date are correct, the company name is incorrect, and the line item extraction is highly inaccurate. The model merged multiple distinct line items into single entries, resulting in a significant loss of detail and an incorrect item count.",
  "failure_reasons": [
    "incorrect_company_name",
    "merged_line_items",
    "missing_line_items"
  ],
  "field_notes": {
    "company": "Extracted the parent company 'HMS Host' instead of the specific restaurant 'ESQUIRE GRILLE'.",
    "address": "Extracted part of the company name as the address field.",
    "line_items": "The model failed to separate individual items and their associated descriptions/notes, instead concatenating them into four large blocks. This caused a mismatch in both the number of items and the individual item descriptions."
  }
}
